public class Solution {
    public int processInstructions(String instructions) {
        // 用一个整数的二进制位表示 8 个 LED 的状态
        int state = 0;

        // 每两个字符构成一条指令
        for (int i = 0; i < instructions.length(); i += 2) {
            // 取出操作类型
            char op = instructions.charAt(i);
            // 取出 LED 编号
            int x = instructions.charAt(i + 1) - '0';

            // 生成第 x 位对应的掩码
            int mask = 1 << x;

            // 根据操作类型执行位运算
            if (op == 'L') {
                // 点亮第 x 个 LED
                state |= mask;
            } else if (op == 'D') {
                // 熄灭第 x 个 LED
                state &= ~mask;
            } else {
                // 切换第 x 个 LED
                state ^= mask;
            }
        }

        // 返回最终结果
        return state;
    }
}
