var processInstructions = function(instructions) {
    // 用一个整数的二进制位表示 8 个 LED 的状态
    let state = 0;

    // 每两个字符构成一条指令
    for (let i = 0; i < instructions.length; i += 2) {
        const cmd = instructions[i];       // 操作类型
        const led = parseInt(instructions[i + 1]);  // LED 编号

        // 根据操作类型执行位运算
        if (cmd === 'L') state |= (1 << led);       // 点亮
        else if (cmd === 'D') state &= ~(1 << led); // 熄灭
        else if (cmd === 'T') state ^= (1 << led);  // 切换
    }

    // 返回最终结果
    return state;
};
