int processInstructions(char* instructions) {
    // 用一个整数的二进制位表示 8 个 LED 的状态
    int state = 0;
    int len = strlen(instructions);

    // 每两个字符构成一条指令
    for (int i = 0; i < len; i += 2) {
        int led = instructions[i + 1] - '0';  // LED 编号

        // 根据操作类型执行位运算
        if (instructions[i] == 'L')
            state |= (1 << led);        // 点亮
        else if (instructions[i] == 'D')
            state &= ~(1 << led);       // 熄灭
        else
            state ^= (1 << led);        // 切换
    }

    // 返回最终结果
    return state;
}
